def build_knowledge_base():
    """Main entry point: build and save the complete knowledge base."""
    print("\n" + "=" * 60)
    print("🧠 SEREIN AI — Knowledge Base Builder")
    print("=" * 60)

    all_entries = []

    # Build from all sources
    all_entries.extend(build_empathetic_dialogues())
    all_entries.extend(build_counsel_chat())
    all_entries.extend(build_mental_health_faq())
    all_entries.extend(build_daily_dialog())

    # Deduplicate by question hash
    seen = set()
    unique_entries = []
    for entry in all_entries:
        h = hashlib.md5(entry['q'].lower().strip().encode()).hexdigest()
        if h not in seen:
            seen.add(h)
            unique_entries.append(entry)

    # Ensure output directory exists
    os.makedirs(os.path.dirname(OUTPUT_PATH), exist_ok=True)

    # Save
    kb = {
        'version': '2.0.0',
        'total_entries': len(unique_entries),
        'sources': ['empathetic_dialogues', 'counsel_chat', 'mental_health_faq', 'daily_dialog', 'custom'],
        'entries': unique_entries,
    }

    with open(OUTPUT_PATH, 'w', encoding='utf-8') as f:
        json.dump(kb, f, ensure_ascii=False, indent=2)

    print(f"\n✅ Knowledge base built successfully!")
    print(f"   📊 Total entries: {len(unique_entries)}")
    print(f"   📁 Saved to: {OUTPUT_PATH}")
    print(f"   📏 File size: {os.path.getsize(OUTPUT_PATH) / 1024:.1f} KB")
    print("=" * 60 + "\n")

    return unique_entries


if __name__ == '__main__':
    build_knowledge_base()
